describe('avatar.json', () => {
  const fx = fixture<{
    avatar_rarity: Case<number, { name: string; icon: string; colour: string }>[];
    rarity_slug: Case<unknown, string>[];
    get_avatar_stage: Case<number, number>[];
    get_branch_stage: Case<{ branch: string; level: number }, number>[];
    determine_avatar_branch: Case<BranchScores, string>[];
    branch_display_name: Case<string, string>[];
    evolution_name: Case<{ branch: string; level: number }, string>[];
    avatar_stage_rows: Case<
      { branch: string; current_level: number },
      { level: number; name: string; stage: number; unlocked: boolean; current: boolean }[]
    >[];
    rank_tiers: [number, string][];
    rank_name: Case<number, string>[];
    rank_ladder: [number, number, string][];
    calculate_starting_level: Case<
      {
        bench_e1rm: number;
        squat_e1rm: number;
        training_years: number;
        physique_score: number;
        leanness_score: number;
      },
      number
    >[];
    next_evolution_info: Case<
      {
        branch: string;
        level: number;
        bench_e1rm: number;
        bf_mid: number | null;
        total_sets: number;
        cardio_minutes: number;
      },
      {
        target_name: string;
        target_level: number;
        requirements: { label: string; current: number; target: number; met: boolean }[];
      }
    >[];
  }>('avatar.json');

  it('avatar_rarity', () => {
    eachCase(fx.avatar_rarity, (c) => expect(avatarRarity(c.input), `level=${c.input}`).toEqual(c.expected));
  });

  it('rarity_slug never throws', () => {
    eachCase(fx.rarity_slug, (c) => expect(raritySlug(c.input), `level=${c.input}`).toBe(c.expected));
  });

  it('get_avatar_stage', () => {
    eachCase(fx.get_avatar_stage, (c) => expect(getAvatarStage(c.input)).toBe(c.expected));
  });

  it('get_branch_stage', () => {
    eachCase(fx.get_branch_stage, (c) =>
      expect(getBranchStage(c.input.branch, c.input.level), JSON.stringify(c.input)).toBe(c.expected)
    );
  });

  it('determine_avatar_branch', () => {
    eachCase(fx.determine_avatar_branch, (c) =>
      expect(determineAvatarBranch(c.input), JSON.stringify(c.input)).toBe(c.expected)
    );
  });

  it('branch_display_name', () => {
    eachCase(fx.branch_display_name, (c) => expect(branchDisplayName(c.input)).toBe(c.expected));
  });

  it('evolution_name (True Adam at 100, both ladders agree)', () => {
    eachCase(fx.evolution_name, (c) =>
      expect(evolutionName(c.input.branch, c.input.level), JSON.stringify(c.input)).toBe(c.expected)
    );
  });

  it('avatar_stage_rows', () => {
    eachCase(fx.avatar_stage_rows, (c) =>
      expect(avatarStageRows(c.input.branch, c.input.current_level), JSON.stringify(c.input)).toEqual(c.expected)
    );
  });

  it('rank ladder', () => {
    expect(fx.rank_tiers.length).toBeGreaterThan(0);
    expect(RANK_TIERS.map((t) => [...t])).toEqual(fx.rank_tiers);
    eachCase(fx.rank_name, (c) => expect(rankName(c.input), `level=${c.input}`).toBe(c.expected));
    expect(fx.rank_ladder.length).toBeGreaterThan(0);
    expect(rankLadder()).toEqual(fx.rank_ladder);
  });

  it('next_evolution_info (evolution requirements per branch)', () => {
    eachCase(fx.next_evolution_info, (c) => {
      const got = nextEvolutionInfo(c.input.branch as never, {
        level: c.input.level,
        benchE1rm: c.input.bench_e1rm,
        bfMid: c.input.bf_mid,
        totalSets: c.input.total_sets,
        cardioMinutes: c.input.cardio_minutes,
      });
      expect(
        {
          target_name: got.targetName,
          target_level: got.targetLevel,
          requirements: got.requirements.map((r) => ({
            label: r.label,
            current: r.current,
            target: r.target,
            met: r.met,
          })),
        },
        JSON.stringify(c.input)
      ).toEqual(c.expected);
    });
  });

  it('calculate_starting_level (onboarding placement)', () => {
    eachCase(fx.calculate_starting_level, (c) =>
      expect(
        calculateStartingLevel(
          c.input.bench_e1rm,
          c.input.squat_e1rm,
          c.input.training_years,
          c.input.physique_score,
          c.input.leanness_score
        ),
        JSON.stringify(c.input)
      ).toBe(c.expected)
    );
  });
});

