describe('bodyfat.json', () => {
  const fx = fixture<{
    navy_body_fat_male: Case<{ height_cm: unknown; waist_cm: unknown; neck_cm: unknown }, number | null>[];
    bodyfat_outputs: Case<
      { weight_kg: unknown; bf_percent: unknown; target_bf: unknown },
      { fat_mass: number | null; lean_mass: number | null; target_weight: number | null; fat_to_lose: number | null }
    >[];
    bodyfat_outputs_default_target: Case<{ weight_kg: number; bf_percent: number }, (number | null)[]>[];
    safe_kg: Case<unknown, string>[];
  }>('bodyfat.json');

  it('navy_body_fat_male, exact doubles', () => {
    eachCase(fx.navy_body_fat_male, (c) =>
      expect(
        navyBodyFatMale(c.input.height_cm, c.input.waist_cm, c.input.neck_cm),
        JSON.stringify(c.input)
      ).toBe(c.expected)
    );
  });

  it('bodyfat_outputs', () => {
    eachCase(fx.bodyfat_outputs, (c) => {
      const [fatMass, leanMass, targetWeight, fatToLose] = bodyfatOutputs(
        c.input.weight_kg,
        c.input.bf_percent,
        c.input.target_bf
      );
      expect(
        { fat_mass: fatMass, lean_mass: leanMass, target_weight: targetWeight, fat_to_lose: fatToLose },
        JSON.stringify(c.input)
      ).toEqual(c.expected);
    });
  });

  it('default target_bf is 10', () => {
    eachCase(fx.bodyfat_outputs_default_target, (c) =>
      expect([...bodyfatOutputs(c.input.weight_kg, c.input.bf_percent)]).toEqual(c.expected)
    );
  });

  it('safe_kg formatting', () => {
    eachCase(fx.safe_kg, (c) => expect(safeKg(c.input), `value=${c.input}`).toBe(c.expected));
  });
});

