// ---------------------------------------------------------------- catalogs

describe('catalogs.json', () => {
  const fx = fixture<{
    achievements_count: number;
    achievements: Record<string, [string, string]>;
    routine: Record<string, string[]>;
    exercise_library: Record<string, string[]>;
    muscle_map_count: number;
    muscle_map: Record<string, string>;
  }>('catalogs.json');

  it('64 achievements, byte-identical strings', () => {
    expect(fx.achievements_count).toBe(64);
    expect(Object.keys(ACHIEVEMENTS).length).toBe(fx.achievements_count);
    expect(
      Object.fromEntries(Object.entries(ACHIEVEMENTS).map(([k, v]) => [k, [...v]]))
    ).toEqual(fx.achievements);
  });

  it('routine and exercise library', () => {
    expect(Object.fromEntries(Object.entries(ROUTINE).map(([k, v]) => [k, [...v]]))).toEqual(fx.routine);
    expect(
      Object.fromEntries(Object.entries(EXERCISE_LIBRARY).map(([k, v]) => [k, [...v]]))
    ).toEqual(fx.exercise_library);
  });

  it('muscle map', () => {
    expect(fx.muscle_map_count).toBe(71);
    expect(MUSCLE_MAP).toEqual(fx.muscle_map);
  });
});
